		import sailpoint.api.IdentityService;
		import sailpoint.object.Identity;
		import sailpoint.object.Link;
		import sailpoint.object.Application;
		import sailpoint.object.Schema;
		import sailpoint.tools.Util;

               
        workflow.put("isSuccess",false);
        workflow.put("inputPassword",inputPassword);
        workflow.put("inputUserName",inputUserName);
        workflow.put("identityDisplayName","");
        workflow.put("managerEmail","");
		workflow.put("applicationName",inputApplication);
        
		String userName = "Username";
		
        try{
          if(Util.isNotNullOrEmpty(inputIdentity) && Util.isNotNullOrEmpty(inputApplication) &&  Util.isNotNullOrEmpty(inputUserName)){
            Identity identityObj = context.getObjectById(Identity.class, inputIdentity);
            Application applicationObj = context.getObjectById(Application.class, inputApplication);
            if(identityObj==null){
              identityObj = context.getObjectByName(Identity.class, inputIdentity);
            }
            if(applicationObj==null){
              applicationObj = context.getObjectByName(Application.class, inputApplication);
            }

            if(identityObj != null){
				if(applicationObj != null) {
					IdentityService iiqService = new IdentityService(context);
					Schema schema = applicationObj.getSchema("account");
					if(schema!=null && schema.getAttributeNames()!=null){
						for(String sName : schema.getAttributeNames()){
							if(userName.equalsIgnoreCase(sName)){
								userName = sName;
								List<Link> appLinks = iiqService.getLinks(identityObj, applicationObj);
								if(appLinks!=null && !appLinks.isEmpty()){
									for(Link link : appLinks){
									  link.setAttribute(sName, inputUserName);
									}
								}
								break;
							}
						}
					}
					context.decache(applicationObj);
				}
				
				workflow.put("identityEmail",identityObj.getEmail());
				workflow.put("identityDisplayName",identityObj.getStringAttribute("displayName"));
				if(identityObj.getManager()!=null && Util.isNotNullOrEmpty(identityObj.getManager().getEmail())){				
					workflow.put("managerEmail",identityObj.getManager().getEmail());
				}
				
				context.saveObject(identityObj);
				context.commitTransaction();
				
				context.decache(identityObj);
				workflow.put("isSuccess",true);
            }
          }
        }catch(GeneralException ex){
          workflow.put("isSuccess",false);
        }

        import javax.faces.application.FacesMessage; 
        import sailpoint.tools.Util;
        List currentMessages = httpSession.getAttribute("sailpoint.web.PageCodeBase.sessionMessages");  
        FacesMessage myMessage = null;
        if(isSuccess){
					String message = "Updated User Name on Account successful for selected identity";
					myMessage = new FacesMessage(FacesMessage.SEVERITY_INFO,message+".","Success");  
        }
        else{
					String message = "Failed To Update.";
					myMessage = new FacesMessage(FacesMessage.SEVERITY_ERROR,message+".","Failure"); 
        }
        List myMessages = new ArrayList();  
        myMessages.add(myMessage);  
        httpSession.setAttribute("sailpoint.web.PageCodeBase.sessionMessages", myMessages);
